use ratatui::{
    layout::{Alignment, Constraint, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, RightPanel};

pub fn render_right_sidebar(f: &mut Frame, state: &mut AppState, area: Rect, border_color: Color) {
    // Full outer border — color reflects hover/drag/focus
    let outer = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(border_color));
    let inner = outer.inner(area);
    f.render_widget(outer, area);

    // Split: tab buttons row (3 lines) + content
    let layout = Layout::vertical([Constraint::Length(3), Constraint::Min(0)]).split(inner);
    let tab_area = layout[0];
    let content_area = layout[1];

    // / Commands | MCPs tab buttons
    let tab_cols = Layout::horizontal([
        Constraint::Ratio(1, 2),
        Constraint::Ratio(1, 2),
    ])
    .split(tab_area);

    let panels = [RightPanel::Skills, RightPanel::Mcps];
    let labels = ["/ Commands", "MCPs"];

    // Store tab button rects for mouse click detection
    state.right_tab_rects = [tab_cols[0], tab_cols[1]];

    for (i, (panel, label)) in panels.iter().zip(labels.iter()).enumerate() {
        let active = &state.layout.right_panel == panel;
        let (border_style, border_type, text_style) = if active {
            (
                Style::default().fg(Color::Cyan),
                BorderType::Rounded,
                Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
            )
        } else {
            (
                Style::default().fg(Color::DarkGray),
                BorderType::Plain,
                Style::default().fg(Color::Gray),
            )
        };
        let block = Block::default()
            .borders(Borders::ALL)
            .border_type(border_type)
            .border_style(border_style);
        let para = Paragraph::new(Line::from(Span::styled(*label, text_style)))
            .block(block)
            .alignment(Alignment::Center);
        f.render_widget(para, tab_cols[i]);
    }

    // Panel content
    match state.layout.right_panel {
        RightPanel::Skills => super::skills::render_skills(f, state, content_area),
        RightPanel::Mcps => {
            let b = Block::default()
                .borders(Borders::ALL)
                .border_type(BorderType::Rounded)
                .border_style(Style::default().fg(Color::DarkGray))
                .title(" MCPs ");
            f.render_widget(b, content_area);
        }
    }
}

