use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, SkillEntry};

pub fn render_skills(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(" Skills ");
    let inner = block.inner(area);
    f.render_widget(block, area);

    let mut lines: Vec<Line> = Vec::new();
    let skills = &state.skills;

    let repo_header = if skills.repo_collapsed { "▶ Repo" } else { "▼ Repo" };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", repo_header, skills.repo.len()),
        Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
    )));
    if !skills.repo_collapsed {
        for s in &skills.repo {
            lines.push(skill_line(s));
        }
    }

    let user_header = if skills.user_collapsed { "▶ User" } else { "▼ User" };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", user_header, skills.user.len()),
        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD),
    )));
    if !skills.user_collapsed {
        for s in &skills.user {
            lines.push(skill_line(s));
        }
    }

    let global_header = if skills.global_collapsed {
        "▶ Global"
    } else {
        "▼ Global"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", global_header, skills.global.len()),
        Style::default()
            .fg(Color::DarkGray)
            .add_modifier(Modifier::BOLD),
    )));
    if !skills.global_collapsed {
        for s in &skills.global {
            lines.push(skill_line(s));
        }
    }

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

fn skill_line(s: &SkillEntry) -> Line<'static> {
    let style = if s.overridden {
        Style::default().fg(Color::DarkGray)
    } else {
        Style::default().fg(Color::White)
    };
    Line::from(Span::styled(format!("  /{}", s.name), style))
}

