use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};

use crate::state::{MessageRole, TabState};

pub fn role_style(role: &MessageRole) -> Style {
    match role {
        MessageRole::User => Style::default().fg(Color::Green),
        MessageRole::Assistant => Style::default().fg(Color::White),
        MessageRole::System => Style::default().fg(Color::DarkGray),
    }
}

pub fn render_chat(f: &mut Frame, tab: &TabState, area: Rect, _focused: bool) {
    let inner = area;

    if tab.messages.is_empty() && tab.streaming.is_none() {
        let placeholder = Paragraph::new("Start a conversation...")
            .style(Style::default().fg(Color::DarkGray));
        f.render_widget(placeholder, inner);
        return;
    }

    let mut lines: Vec<Line> = Vec::new();

    for msg in &tab.messages {
        let prefix = match msg.role {
            MessageRole::User => "You: ",
            MessageRole::Assistant => "Claude: ",
            MessageRole::System => "System: ",
        };
        let style = role_style(&msg.role);
        lines.push(Line::from(Span::styled(
            prefix,
            style.add_modifier(Modifier::BOLD),
        )));
        for content_line in msg.content.lines() {
            lines.push(Line::from(Span::styled(
                format!("  {}", content_line),
                Style::default().fg(Color::White),
            )));
        }
        lines.push(Line::default());
    }

    if let Some(chunk) = &tab.streaming {
        lines.push(Line::from(Span::styled(
            "Claude: ",
            Style::default()
                .fg(Color::White)
                .add_modifier(Modifier::BOLD),
        )));
        for content_line in chunk.lines() {
            lines.push(Line::from(Span::styled(
                format!("  {}", content_line),
                Style::default().fg(Color::White),
            )));
        }
        lines.push(Line::from(Span::styled(
            "  \u{258a}",
            Style::default().fg(Color::Cyan),
        )));
    }

    let total_lines = lines.len();
    let visible_height = inner.height as usize;
    let scroll = if total_lines > visible_height {
        (total_lines - visible_height) as u16
    } else {
        0
    };

    let para = Paragraph::new(lines).scroll((scroll, 0));
    f.render_widget(para, inner);
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::state::MessageRole;

    #[test]
    fn user_message_has_green_style() {
        let style = role_style(&MessageRole::User);
        assert_eq!(style.fg, Some(ratatui::style::Color::Green));
    }

    #[test]
    fn assistant_message_has_white_style() {
        let style = role_style(&MessageRole::Assistant);
        assert_eq!(style.fg, Some(ratatui::style::Color::White));
    }
}

