// Mouse: scroll — route by where the mouse currently is
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::ScrollUp,
    ..
} => {
    let mc = state.mouse_col;
    let mr = state.mouse_row;
    let in_left = state.layout.left_visible && {
        let r = state.sessions_panel_rect; // also covers git/files (same column)
        mc < r.x + r.width
    };
    let in_sessions = in_left && state.layout.left_panel == crate::state::LeftPanel::Sessions;
    let in_files    = in_left && state.layout.left_panel == crate::state::LeftPanel::Files;
    let in_chat = { let r = state.chat_area_rect; mc >= r.x && mc < r.x + r.width && mr >= r.y && mr < r.y + r.height };

    if in_sessions {
        state.sessions_scroll = state.sessions_scroll.saturating_sub(1);
    } else if in_files {
        if state.files.scroll > 0 { state.files.scroll -= 1; }
    } else if in_chat {
        if let Some(tab) = state.active_tab_mut() {
            tab.chat_scroll = tab.chat_scroll.saturating_sub(3);
        }
    } else if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::FileViewer { scroll, .. } => { *scroll = scroll.saturating_sub(3); }
            crate::state::TabKind::DiffViewer { scroll, .. } => { *scroll = scroll.saturating_sub(3); }
            _ => {}
        }
    }
}
AppEvent::Mouse {
    kind: crossterm::event::MouseEventKind::ScrollDown,
    ..
} => {
    let mc = state.mouse_col;
    let mr = state.mouse_row;
    let in_left = state.layout.left_visible && {
        let r = state.sessions_panel_rect;
        mc < r.x + r.width
    };
    let in_sessions = in_left && state.layout.left_panel == crate::state::LeftPanel::Sessions;
    let in_files    = in_left && state.layout.left_panel == crate::state::LeftPanel::Files;
    let in_chat = { let r = state.chat_area_rect; mc >= r.x && mc < r.x + r.width && mr >= r.y && mr < r.y + r.height };

    if in_sessions {
        let total   = state.session_entries.len();
        let panel_h = state.sessions_panel_rect.height;
        let visible = if panel_h > 2 { ((panel_h - 2) / 4) as usize } else { 5 };
        let max     = total.saturating_sub(visible);
        if state.sessions_scroll < max { state.sessions_scroll += 1; }
    } else if in_files {
        let total = state.files.nodes.len();
        let h     = state.files_panel_rect.height as usize;
        if state.files.scroll + h < total { state.files.scroll += 1; }
    } else if in_chat {
        if let Some(tab) = state.active_tab_mut() {
            tab.chat_scroll += 3;
        }
    } else if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::FileViewer { scroll, .. } => { *scroll += 3; }
            crate::state::TabKind::DiffViewer { scroll, .. } => { *scroll += 3; }
            _ => {}
        }
    }
}
AppEvent::Key { code, modifiers } if matches!(state.layout.focus, crate::state::Focus::Input) => {
    use crossterm::event::KeyCode as KC;
    use crossterm::event::KeyModifiers as KM;

