mod tests {
    use super::*;
    use crate::state::MessageRole;

    #[test]
    fn user_message_has_green_style() {
        let style = role_style(&MessageRole::User);
        assert_eq!(style.fg, Some(ratatui::style::Color::Green));
    }

    #[test]
    fn assistant_message_has_white_style() {
        let style = role_style(&MessageRole::Assistant);
        assert_eq!(style.fg, Some(ratatui::style::Color::White));
    }
}

