use ratatui::{
    layout::{Alignment, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::Paragraph,
    Frame,
};

use crate::state::{MessageRole, TabState};

pub fn role_style(role: &MessageRole) -> Style {
    match role {
        MessageRole::User => Style::default().fg(Color::Green),
        MessageRole::Assistant => Style::default().fg(Color::White),
        MessageRole::System => Style::default().fg(Color::DarkGray),
    }
}

pub fn render_chat(f: &mut Frame, tab: &mut TabState, area: Rect, _focused: bool) {
    let inner = area;

    if tab.messages.is_empty() && tab.streaming.is_none() {
        let placeholder = Paragraph::new("Start a conversation...")
            .style(Style::default().fg(Color::DarkGray));
        f.render_widget(placeholder, inner);
        return;
    }

    let width = inner.width as usize;

    // Build lines with alignment info
    let mut entries: Vec<(Line, Alignment)> = Vec::new();

    for msg in &tab.messages {
        let (prefix, align) = match msg.role {
            MessageRole::User => ("You: ", Alignment::Right),
            MessageRole::Assistant => ("Claude: ", Alignment::Left),
            MessageRole::System => ("System: ", Alignment::Center),
        };
        let style = role_style(&msg.role);
        entries.push((
            Line::from(Span::styled(prefix, style.add_modifier(Modifier::BOLD))),
            align,
        ));
        for content_line in msg.content.lines() {
            // Word-wrap long lines
            let text = format!("  {}", content_line);
            for wrapped in wrap_line(&text, width) {
                entries.push((
                    Line::from(Span::styled(wrapped, Style::default().fg(Color::White))),
                    align,
                ));
            }
        }
        entries.push((Line::default(), align));
    }

    if let Some(chunk) = &tab.streaming {
        entries.push((
            Line::from(Span::styled(
                "Claude: ",
                Style::default().fg(Color::White).add_modifier(Modifier::BOLD),
            )),
            Alignment::Left,
        ));
        for content_line in chunk.lines() {
            let text = format!("  {}", content_line);
            for wrapped in wrap_line(&text, width) {
                entries.push((
                    Line::from(Span::styled(wrapped, Style::default().fg(Color::White))),
                    Alignment::Left,
                ));
            }
        }
        entries.push((
            Line::from(Span::styled("\u{258a}", Style::default().fg(Color::Cyan))),
            Alignment::Left,
        ));
    }

    let total_lines = entries.len();
    let visible_height = inner.height as usize;

    // Auto-scroll to bottom when chat_scroll is 0 (default)
    let max_scroll = total_lines.saturating_sub(visible_height);

    // Clamp chat_scroll
    if tab.chat_scroll > max_scroll {
        tab.chat_scroll = max_scroll;
    }

    // If chat_scroll == 0, show from the bottom (auto-follow)
    let scroll_offset = if tab.chat_scroll == 0 {
        max_scroll
    } else {
        max_scroll.saturating_sub(tab.chat_scroll)
    };

    // Render each visible line with its own alignment
    let start = scroll_offset;
    let end = (start + visible_height).min(total_lines);

    for (i, idx) in (start..end).enumerate() {
        let (line, align) = &entries[idx];
        let row_rect = Rect {
            x: inner.x,
            y: inner.y + i as u16,
            width: inner.width,
            height: 1,
        };
        let para = Paragraph::new(line.clone()).alignment(*align);
        f.render_widget(para, row_rect);
    }
}

/// Simple word-wrap: split line into chunks of at most `width` characters.
fn wrap_line(text: &str, width: usize) -> Vec<String> {
    if width == 0 {
        return vec![text.to_string()];
    }
    if text.len() <= width {
        return vec![text.to_string()];
    }
    let mut result = Vec::new();
    let mut remaining = text;
    while remaining.len() > width {
        // Try to break at a space
        let break_at = remaining[..width]
            .rfind(' ')
            .unwrap_or(width);
        let break_at = if break_at == 0 { width } else { break_at };
        result.push(remaining[..break_at].to_string());
        remaining = remaining[break_at..].trim_start();
    }
    if !remaining.is_empty() {
        result.push(remaining.to_string());
    }
    result
}

