use ratatui::{
    layout::{Alignment, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::Paragraph,
    Frame,
};

use crate::state::{MessageRole, TabState};

pub fn role_style(role: &MessageRole) -> Style {
    match role {
        MessageRole::User => Style::default().fg(Color::Green),
        MessageRole::Assistant => Style::default().fg(Color::White),
        MessageRole::System => Style::default().fg(Color::DarkGray),
    }
}

/// Bubble width as fraction of chat area
const BUBBLE_WIDTH_RATIO: f32 = 0.75;
/// Horizontal padding inside bubble
const BUBBLE_PAD: usize = 1;

pub fn render_chat(f: &mut Frame, tab: &mut TabState, area: Rect, _focused: bool) {
    let inner = area;

    if tab.messages.is_empty() && tab.streaming.is_none() {
        let placeholder = Paragraph::new("Start a conversation...")
            .style(Style::default().fg(Color::DarkGray));
        f.render_widget(placeholder, inner);
        return;
    }

    let full_width = inner.width as usize;
    let bubble_width = ((full_width as f32) * BUBBLE_WIDTH_RATIO) as usize;
    let content_width = bubble_width.saturating_sub(BUBBLE_PAD * 2 + 2); // 2 for border chars

    // Each rendered row: (Line, Alignment)
    let mut rows: Vec<(Line, Alignment)> = Vec::new();

    let all_messages: Vec<_> = tab.messages.iter().collect();
    build_message_rows(&all_messages, content_width, bubble_width, full_width, &mut rows);

    if let Some(chunk) = &tab.streaming {
        build_streaming_rows(chunk, content_width, bubble_width, full_width, &mut rows);
    }

    let total_lines = rows.len();
    let visible_height = inner.height as usize;
    let max_scroll = total_lines.saturating_sub(visible_height);

    // Clamp
    if tab.chat_scroll > max_scroll {
        tab.chat_scroll = max_scroll;
    }

    // chat_scroll = lines scrolled UP from bottom. 0 = at bottom (auto-follow).
    let scroll_offset = max_scroll.saturating_sub(tab.chat_scroll);

    let start = scroll_offset;
    let end = (start + visible_height).min(total_lines);

    for (i, idx) in (start..end).enumerate() {
        let (line, align) = &rows[idx];
        let row_rect = Rect {
            x: inner.x,
            y: inner.y + i as u16,
            width: inner.width,
            height: 1,
        };
        let para = Paragraph::new(line.clone()).alignment(*align);
        f.render_widget(para, row_rect);
    }
}

fn build_message_rows<'a>(
    messages: &[&crate::state::ChatMessage],
    content_width: usize,
    bubble_width: usize,
    _full_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment)>,
) {
    for msg in messages {
        let (role_label, align, border_color, text_color) = match msg.role {
            MessageRole::User => ("You", Alignment::Right, Color::Green, Color::White),
            MessageRole::Assistant => ("Claude", Alignment::Left, Color::DarkGray, Color::White),
            MessageRole::System => ("System", Alignment::Center, Color::DarkGray, Color::DarkGray),
        };

        let role_style = Style::default().fg(border_color).add_modifier(Modifier::BOLD);
        let border_style = Style::default().fg(border_color);

        // Top border: ╭─ Role ──...──╮
        let label = format!(" {} ", role_label);
        let remaining = bubble_width.saturating_sub(3 + label.len()); // 1 for ╭, 1 for ─, 1 for ╮
        let top = Line::from(vec![
            Span::styled("╭─", border_style),
            Span::styled(label, role_style),
            Span::styled("─".repeat(remaining).chars().take(remaining).collect::<String>() + "╮", border_style),
        ]);
        rows.push((top, align));

        // Content lines
        let wrapped = wrap_text(&msg.content, content_width);
        for line_text in &wrapped {
            let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + line_text.chars().count() + BUBBLE_PAD);
            let content_line = Line::from(vec![
                Span::styled("│", border_style),
                Span::raw(" ".repeat(BUBBLE_PAD)),
                Span::styled(line_text.clone(), Style::default().fg(text_color)),
                Span::raw(" ".repeat(pad_right + BUBBLE_PAD)),
                Span::styled("│", border_style),
            ]);
            rows.push((content_line, align));
        }

        // Bottom border: ╰──...──╯
        let bottom_fill = bubble_width.saturating_sub(2);
        let bottom = Line::from(vec![
            Span::styled("╰", border_style),
            Span::styled("─".repeat(bottom_fill), border_style),
            Span::styled("╯", border_style),
        ]);
        rows.push((bottom, align));

        // Spacing
        rows.push((Line::default(), align));
    }
}

fn build_streaming_rows<'a>(
    chunk: &str,
    content_width: usize,
    bubble_width: usize,
    _full_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment)>,
) {
    let border_style = Style::default().fg(Color::DarkGray);
    let role_style = Style::default().fg(Color::DarkGray).add_modifier(Modifier::BOLD);

    let label = " Claude ";
    let remaining = bubble_width.saturating_sub(3 + label.len());
    let top = Line::from(vec![
        Span::styled("╭─", border_style),
        Span::styled(label, role_style),
        Span::styled("─".repeat(remaining) + "╮", border_style),
    ]);
    rows.push((top, Alignment::Left));

    let wrapped = wrap_text(chunk, content_width);
    for line_text in &wrapped {
        let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + line_text.chars().count() + BUBBLE_PAD);
        let content_line = Line::from(vec![
            Span::styled("│", border_style),
            Span::raw(" ".repeat(BUBBLE_PAD)),
            Span::styled(line_text.clone(), Style::default().fg(Color::White)),
            Span::raw(" ".repeat(pad_right + BUBBLE_PAD)),
            Span::styled("│", border_style),
        ]);
        rows.push((content_line, Alignment::Left));
    }

    // Cursor line
    let cursor_text = "\u{258a}";
    let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + 1 + BUBBLE_PAD);
    let cursor_line = Line::from(vec![
        Span::styled("│", border_style),
        Span::raw(" ".repeat(BUBBLE_PAD)),
        Span::styled(cursor_text, Style::default().fg(Color::Cyan)),
        Span::raw(" ".repeat(pad_right + BUBBLE_PAD)),
        Span::styled("│", border_style),
    ]);
    rows.push((cursor_line, Alignment::Left));

    let bottom_fill = bubble_width.saturating_sub(2);
    let bottom = Line::from(vec![
        Span::styled("╰", border_style),
        Span::styled("─".repeat(bottom_fill), border_style),
        Span::styled("╯", border_style),
    ]);
    rows.push((bottom, Alignment::Left));
}

/// Wrap text content into lines of at most `width` chars, respecting existing newlines.
fn wrap_text(text: &str, width: usize) -> Vec<String> {
    let mut result = Vec::new();
    if text.is_empty() {
        result.push(String::new());
        return result;
    }
    for line in text.lines() {
        if line.is_empty() {
            result.push(String::new());
            continue;
        }
        for wrapped in wrap_line(line, width) {
            result.push(wrapped);
        }
    }
    // If text ends with newline, lines() won't yield trailing empty
    if text.ends_with('\n') {
        result.push(String::new());
    }
    result
}

/// Word-wrap a single line into chunks of at most `width` display columns.
fn wrap_line(text: &str, width: usize) -> Vec<String> {
    if width == 0 || text.is_empty() {
        return vec![text.to_string()];
    }
    let chars: Vec<char> = text.chars().collect();
    if chars.len() <= width {
        return vec![text.to_string()];
    }
    let mut result = Vec::new();
    let mut start = 0;
    while start < chars.len() {
        let end = (start + width).min(chars.len());
        if end >= chars.len() {
            result.push(chars[start..].iter().collect());
            break;
        }
        let mut break_at = end;
        for i in (start..end).rev() {
            if chars[i] == ' ' {
                break_at = i;
                break;
            }
        }
        if break_at == start {
            break_at = end;
        }
        result.push(chars[start..break_at].iter().collect());
        start = break_at;
        while start < chars.len() && chars[start] == ' ' {
            start += 1;
        }
    }
    result
}

