fn push_spans_content_row<'a>(
    spans: Vec<Span<'a>>,
    border_style: Style,
    bubble_width: usize,
    content_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment)>,
    align: Alignment,
) {
    // Truncate spans to fit content_width
    let mut truncated: Vec<Span<'a>> = Vec::new();
    let mut remaining = content_width;
    for span in spans {
        let char_count = span.content.chars().count();
        if remaining == 0 {
            break;
