use std::sync::OnceLock;

use ratatui::{
    layout::{Alignment, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::Paragraph,
    Frame,
};
use syntect::{
    easy::HighlightLines,
    highlighting::{Style as SyntectStyle, ThemeSet},
    parsing::SyntaxSet,
    util::LinesWithEndings,
};

use crate::state::{ChatLink, LinkTarget, MessageRole, TabState};

// ── Syntect singletons ──

static SYNTAX_SET: OnceLock<SyntaxSet> = OnceLock::new();
static THEME_SET: OnceLock<ThemeSet> = OnceLock::new();

fn syntax_set() -> &'static SyntaxSet {
    SYNTAX_SET.get_or_init(SyntaxSet::load_defaults_newlines)
}
fn theme_set() -> &'static ThemeSet {
    THEME_SET.get_or_init(ThemeSet::load_defaults)
}
fn to_ratatui_color(c: syntect::highlighting::Color) -> Color {
    Color::Rgb(c.r, c.g, c.b)
}
fn to_ratatui_style(s: SyntectStyle) -> Style {
    Style::default().fg(to_ratatui_color(s.foreground))
}

// ── Constants ──

const BUBBLE_WIDTH_RATIO: f32 = 0.75;
const BUBBLE_PAD: usize = 1;

const COLOR_USER: Color = Color::Green;
const COLOR_ASSISTANT: Color = Color::DarkGray;
const COLOR_SYSTEM: Color = Color::DarkGray;
const COLOR_TOOL: Color = Color::Rgb(80, 140, 220);
const COLOR_LINK: Color = Color::Rgb(100, 160, 255);

// ── Link detection ──

#[derive(Debug, Clone)]
struct InlineLink {
    start: usize, // char offset in the line
    end: usize,
    target: LinkTarget,
}

/// Find URLs and local file/dir paths in a text line.
fn detect_links(text: &str, cwd: &std::path::Path) -> Vec<InlineLink> {
    let mut links = Vec::new();
    let chars: Vec<char> = text.chars().collect();
    let len = chars.len();
    let mut i = 0;

    while i < len {
        // URL detection: http:// or https://
        if i + 8 < len {
            let slice: String = chars[i..].iter().collect();
            if slice.starts_with("http://") || slice.starts_with("https://") {
                let end = find_url_end(&chars, i);
                let url: String = chars[i..end].iter().collect();
                links.push(InlineLink {
                    start: i,
                    end,
                    target: LinkTarget::Url(url),
                });
                i = end;
                continue;
            }
        }

        // File path detection: starts with ./ or / and looks like a path
        if chars[i] == '/' || (chars[i] == '.' && i + 1 < len && chars[i + 1] == '/') {
            let end = find_path_end(&chars, i);
            if end > i + 1 {
                let path_str: String = chars[i..end].iter().collect();
                let full_path = if path_str.starts_with('/') {
                    std::path::PathBuf::from(&path_str)
                } else {
                    cwd.join(&path_str)
                };
                if full_path.exists() {
                    links.push(InlineLink {
                        start: i,
                        end,
                        target: LinkTarget::FilePath(full_path.to_string_lossy().to_string()),
                    });
                    i = end;
                    continue;
                }
            }
        }

        i += 1;
    }
    links
}

fn find_url_end(chars: &[char], start: usize) -> usize {
    let mut i = start;
    while i < chars.len() {
        let c = chars[i];
        if c.is_whitespace() || c == ')' || c == ']' || c == '>' || c == '"' || c == '\'' {
            break;
        }
        i += 1;
    }
    // Strip trailing punctuation
    while i > start && matches!(chars[i - 1], '.' | ',' | ';' | ':' | '!' | '?') {
        i -= 1;
    }
    i
}

fn find_path_end(chars: &[char], start: usize) -> usize {
    let mut i = start;
    while i < chars.len() {
        let c = chars[i];
        if c.is_whitespace() || c == ')' || c == ']' || c == '>' || c == '"' || c == '\'' || c == ',' || c == ';' {
            break;
        }
        i += 1;
    }
    i
}

/// Split a text line into spans, with links underlined in blue.
/// Returns (spans, link_infos) where link_infos contains (char_offset, len, target).
fn spans_with_links<'a>(
    text: &str,
    base_style: Style,
    links: &[InlineLink],
) -> (Vec<Span<'a>>, Vec<(usize, usize, LinkTarget)>) {
    let mut spans = Vec::new();
    let mut link_infos = Vec::new();
    let chars: Vec<char> = text.chars().collect();
    let mut pos = 0;

    for link in links {
        if link.start > pos {
            let plain: String = chars[pos..link.start].iter().collect();
            spans.push(Span::styled(plain, base_style));
        }
        let link_text: String = chars[link.start..link.end].iter().collect();
        let link_style = Style::default()
            .fg(COLOR_LINK)
            .add_modifier(Modifier::UNDERLINED);
        link_infos.push((link.start, link.end - link.start, link.target.clone()));
        spans.push(Span::styled(link_text, link_style));
        pos = link.end;
    }

    if pos < chars.len() {
        let rest: String = chars[pos..].iter().collect();
        spans.push(Span::styled(rest, base_style));
    }

    if spans.is_empty() {
        spans.push(Span::styled(text.to_string(), base_style));
    }

    (spans, link_infos)
}

// ── Render ──

pub fn render_chat(f: &mut Frame, tab: &mut TabState, area: Rect, _focused: bool, chat_links: &mut Vec<ChatLink>, cwd: &std::path::Path) {
    let inner = area;
    chat_links.clear();

    if tab.messages.is_empty() && tab.streaming.is_none() {
        let placeholder = Paragraph::new("Start a conversation...")
            .style(Style::default().fg(Color::DarkGray));
        f.render_widget(placeholder, inner);
        return;
    }

    let full_width = inner.width as usize;
    let bubble_width = ((full_width as f32) * BUBBLE_WIDTH_RATIO) as usize;
    let content_width = bubble_width.saturating_sub(BUBBLE_PAD * 2 + 2);

    // Each row: (Line, Alignment, Option<links for this row>)
    let mut rows: Vec<(Line, Alignment, Vec<(usize, usize, LinkTarget)>)> = Vec::new();

    for msg in &tab.messages {
        let (label, align, border_color, text_color) = match msg.role {
            MessageRole::User => ("You", Alignment::Right, COLOR_USER, Color::White),
            MessageRole::Assistant => ("Claude", Alignment::Left, COLOR_ASSISTANT, Color::White),
            MessageRole::System => ("System", Alignment::Center, COLOR_SYSTEM, COLOR_SYSTEM),
            MessageRole::ToolUse => ("Tool", Alignment::Left, COLOR_TOOL, Color::White),
            MessageRole::ToolResult => ("Result", Alignment::Left, COLOR_TOOL, Color::White),
        };

        build_bubble(label, &msg.content, align, border_color, text_color, bubble_width, content_width, &mut rows, cwd);
        rows.push((Line::default(), align, Vec::new()));
    }

    if let Some(chunk) = &tab.streaming {
        build_bubble("Claude", chunk, Alignment::Left, COLOR_ASSISTANT, Color::White, bubble_width, content_width, &mut rows, cwd);
        let border_style = Style::default().fg(COLOR_ASSISTANT);
        let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + 1 + BUBBLE_PAD);
        rows.push((Line::from(vec![
            Span::styled("│", border_style),
            Span::raw(" ".repeat(BUBBLE_PAD)),
            Span::styled("\u{258a}", Style::default().fg(Color::Cyan)),
            Span::raw(" ".repeat(pad_right + BUBBLE_PAD)),
            Span::styled("│", border_style),
        ]), Alignment::Left, Vec::new()));
        let bottom_fill = bubble_width.saturating_sub(2);
        rows.push((Line::from(vec![
            Span::styled("╰", border_style),
            Span::styled("─".repeat(bottom_fill), border_style),
            Span::styled("╯", border_style),
        ]), Alignment::Left, Vec::new()));
    }

    // Scroll
    let total_lines = rows.len();
    let visible_height = inner.height as usize;
    let max_scroll = total_lines.saturating_sub(visible_height);

    if tab.chat_scroll > max_scroll {
        tab.chat_scroll = max_scroll;
    }

    let scroll_offset = max_scroll.saturating_sub(tab.chat_scroll);
    let start = scroll_offset;
    let end = (start + visible_height).min(total_lines);

    for (i, idx) in (start..end).enumerate() {
        let (line, align, ref link_infos) = rows[idx];
        let screen_row = inner.y + i as u16;
        let row_rect = Rect {
            x: inner.x,
            y: screen_row,
            width: inner.width,
            height: 1,
        };

        // Calculate actual X offset based on alignment
        let line_width: usize = line.spans.iter().map(|s| s.content.chars().count()).sum();
        let x_offset = match align {
            Alignment::Right => inner.x + (inner.width as usize).saturating_sub(line_width) as u16,
            Alignment::Center => inner.x + ((inner.width as usize).saturating_sub(line_width) / 2) as u16,
            Alignment::Left => inner.x,
        };

        // Register links with screen positions
        // Links char offsets are relative to content inside the bubble (after │ + padding)
        let border_offset = 1 + BUBBLE_PAD; // │ + pad
        for (char_off, char_len, target) in link_infos {
            let col_start = x_offset + (border_offset + char_off) as u16;
            let col_end = col_start + *char_len as u16;
            chat_links.push(ChatLink {
                row: screen_row,
                col_start,
                col_end,
                target: target.clone(),
            });
        }

        let para = Paragraph::new(line.clone()).alignment(align);
        f.render_widget(para, row_rect);
    }
}

// ── Bubble builder ──

fn build_bubble<'a>(
    label: &str,
    content: &str,
    align: Alignment,
    border_color: Color,
    text_color: Color,
    bubble_width: usize,
    content_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment, Vec<(usize, usize, LinkTarget)>)>,
    cwd: &std::path::Path,
) {
    let border_style = Style::default().fg(border_color);
    let role_style = Style::default().fg(border_color).add_modifier(Modifier::BOLD);

    // Top border
    let tag = format!(" {} ", label);
    let remaining = bubble_width.saturating_sub(3 + tag.len());
    rows.push((Line::from(vec![
        Span::styled("╭─", border_style),
        Span::styled(tag, role_style),
        Span::styled("─".repeat(remaining) + "╮", border_style),
    ]), align, Vec::new()));

    // Content — parse for code blocks
    let segments = parse_content(content);
    for seg in &segments {
        match seg {
            ContentSegment::Text(text) => {
                for line_text in wrap_text(text, content_width) {
                    let links = detect_links(&line_text, cwd);
                    if links.is_empty() {
                        push_content_row(&line_text, text_color, border_style, bubble_width, content_width, rows, align);
                    } else {
                        push_linked_content_row(&line_text, text_color, border_style, bubble_width, content_width, &links, rows, align);
                    }
                }
            }
            ContentSegment::Code { lang, code } => {
                // Code header
                let header = format!("── {} ", if lang.is_empty() { "code" } else { lang });
                let header_pad = content_width.saturating_sub(header.chars().count());
                push_styled_content_row(
                    vec![
                        Span::styled(header, Style::default().fg(Color::DarkGray)),
                        Span::styled("─".repeat(header_pad), Style::default().fg(Color::DarkGray)),
                    ],
                    border_style, bubble_width, rows, align,
                );

                let highlighted = highlight_code(code, lang, content_width);
                for hl_line in highlighted {
                    push_spans_content_row(hl_line, border_style, bubble_width, content_width, rows, align);
                }

                let footer_pad = content_width;
                push_styled_content_row(
                    vec![Span::styled("─".repeat(footer_pad), Style::default().fg(Color::DarkGray))],
                    border_style, bubble_width, rows, align,
                );
            }
        }
    }

    // Bottom border
    let bottom_fill = bubble_width.saturating_sub(2);
    rows.push((Line::from(vec![
        Span::styled("╰", border_style),
        Span::styled("─".repeat(bottom_fill), border_style),
        Span::styled("╯", border_style),
    ]), align, Vec::new()));
}

fn push_content_row<'a>(
    text: &str,
    text_color: Color,
    border_style: Style,
    bubble_width: usize,
    content_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment, Vec<(usize, usize, LinkTarget)>)>,
    align: Alignment,
) {
    let display: String = text.chars().take(content_width).collect();
    let char_count = display.chars().count();
    let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + char_count + BUBBLE_PAD);
    rows.push((Line::from(vec![
        Span::styled("│", border_style),
        Span::raw(" ".repeat(BUBBLE_PAD)),
        Span::styled(display, Style::default().fg(text_color)),
        Span::raw(" ".repeat(pad_right + BUBBLE_PAD)),
        Span::styled("│", border_style),
    ]), align, Vec::new()));
}

fn push_linked_content_row<'a>(
    text: &str,
    text_color: Color,
    border_style: Style,
    bubble_width: usize,
    content_width: usize,
    links: &[InlineLink],
    rows: &mut Vec<(Line<'a>, Alignment, Vec<(usize, usize, LinkTarget)>)>,
    align: Alignment,
) {
    let display: String = text.chars().take(content_width).collect();
    let base_style = Style::default().fg(text_color);
    let (content_spans, link_infos) = spans_with_links(&display, base_style, links);

    let char_count: usize = content_spans.iter().map(|s| s.content.chars().count()).sum();
    let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + char_count + BUBBLE_PAD);

    let mut all_spans = vec![
        Span::styled("│", border_style),
        Span::raw(" ".repeat(BUBBLE_PAD)),
    ];
    all_spans.extend(content_spans);
    all_spans.push(Span::raw(" ".repeat(pad_right + BUBBLE_PAD)));
    all_spans.push(Span::styled("│", border_style));

    rows.push((Line::from(all_spans), align, link_infos));
}

fn push_styled_content_row<'a>(
    spans: Vec<Span<'a>>,
    border_style: Style,
    bubble_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment, Vec<(usize, usize, LinkTarget)>)>,
    align: Alignment,
) {
    let text_len: usize = spans.iter().map(|s| s.content.chars().count()).sum();
    let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + text_len + BUBBLE_PAD);
    let mut all_spans = vec![
        Span::styled("│", border_style),
        Span::raw(" ".repeat(BUBBLE_PAD)),
    ];
    all_spans.extend(spans);
    all_spans.push(Span::raw(" ".repeat(pad_right + BUBBLE_PAD)));
    all_spans.push(Span::styled("│", border_style));
    rows.push((Line::from(all_spans), align, Vec::new()));
}

fn push_spans_content_row<'a>(
    spans: Vec<Span<'a>>,
    border_style: Style,
    bubble_width: usize,
    content_width: usize,
    rows: &mut Vec<(Line<'a>, Alignment, Vec<(usize, usize, LinkTarget)>)>,
    align: Alignment,
) {
    let mut truncated: Vec<Span<'a>> = Vec::new();
    let mut remaining = content_width;
    for span in spans {
        let char_count = span.content.chars().count();
        if remaining == 0 {
            break;
        }
        if char_count <= remaining {
            remaining -= char_count;
            truncated.push(span);
        } else {
            let text: String = span.content.chars().take(remaining).collect();
            truncated.push(Span::styled(text, span.style));
            remaining = 0;
        }
    }
    let used: usize = truncated.iter().map(|s| s.content.chars().count()).sum();
    let pad_right = bubble_width.saturating_sub(2 + BUBBLE_PAD + used + BUBBLE_PAD);
    let mut all_spans = vec![
        Span::styled("│", border_style),
        Span::raw(" ".repeat(BUBBLE_PAD)),
    ];
    all_spans.extend(truncated);
    all_spans.push(Span::raw(" ".repeat(pad_right + BUBBLE_PAD)));
    all_spans.push(Span::styled("│", border_style));
    rows.push((Line::from(all_spans), align, Vec::new()));
}

// ── Code highlighting ──

fn highlight_code<'a>(code: &str, lang: &str, _max_width: usize) -> Vec<Vec<Span<'a>>> {
    let ss = syntax_set();
    let ts = theme_set();
    let theme = ts.themes.get("base16-ocean.dark")
        .or_else(|| ts.themes.get("Solarized (dark)"))
        .or_else(|| ts.themes.values().next())
        .unwrap();

    let syntax = if !lang.is_empty() {
        ss.find_syntax_by_token(lang)
            .unwrap_or_else(|| ss.find_syntax_plain_text())
    } else {
        ss.find_syntax_plain_text()
    };

    let mut hl = HighlightLines::new(syntax, theme);
    let mut result = Vec::new();

    for line in LinesWithEndings::from(code) {
        let ranges = match hl.highlight_line(line, ss) {
            Ok(r) => r,
            Err(_) => {
                result.push(vec![Span::styled(
                    line.trim_end_matches('\n').to_string(),
                    Style::default().fg(Color::White),
                )]);
                continue;
            }
        };
        let spans: Vec<Span> = ranges.iter().map(|(style, text)| {
            Span::styled(
                text.trim_end_matches('\n').to_string(),
                to_ratatui_style(*style),
            )
        }).collect();
        result.push(spans);
    }
    result
}

// ── Content parsing ──

enum ContentSegment {
    Text(String),
    Code { lang: String, code: String },
}

fn parse_content(content: &str) -> Vec<ContentSegment> {
    let mut segments = Vec::new();
    let mut current_text = String::new();
    let mut in_code = false;
    let mut code_lang = String::new();
    let mut code_buf = String::new();

    for line in content.lines() {
        if !in_code && line.starts_with("```") {
            if !current_text.is_empty() {
                segments.push(ContentSegment::Text(current_text.clone()));
                current_text.clear();
            }
            code_lang = line.trim_start_matches('`').trim().to_string();
            code_buf.clear();
            in_code = true;
        } else if in_code && line.starts_with("```") {
            segments.push(ContentSegment::Code {
                lang: code_lang.clone(),
                code: code_buf.clone(),
            });
            code_lang.clear();
            code_buf.clear();
            in_code = false;
        } else if in_code {
            if !code_buf.is_empty() {
                code_buf.push('\n');
            }
            code_buf.push_str(line);
        } else {
            if !current_text.is_empty() {
                current_text.push('\n');
            }
            current_text.push_str(line);
        }
    }

    if in_code {
        segments.push(ContentSegment::Code {
            lang: code_lang,
            code: code_buf,
        });
    } else if !current_text.is_empty() {
        segments.push(ContentSegment::Text(current_text));
    }

    segments
}

// ── Word wrapping ──

fn wrap_text(text: &str, width: usize) -> Vec<String> {
    let mut result = Vec::new();
    if text.is_empty() {
        result.push(String::new());
        return result;
    }
    for line in text.lines() {
        if line.is_empty() {
            result.push(String::new());
            continue;
        }
        result.extend(wrap_line(line, width));
    }
    if text.ends_with('\n') {
        result.push(String::new());
    }
    result
}

fn wrap_line(text: &str, width: usize) -> Vec<String> {
    if width == 0 || text.is_empty() {
        return vec![text.to_string()];
    }
    let chars: Vec<char> = text.chars().collect();
    if chars.len() <= width {
        return vec![text.to_string()];
    }
    let mut result = Vec::new();
    let mut start = 0;
    while start < chars.len() {
        let end = (start + width).min(chars.len());
        if end >= chars.len() {
            result.push(chars[start..].iter().collect());
            break;
        }
        let mut break_at = end;
        for i in (start..end).rev() {
            if chars[i] == ' ' {
                break_at = i;
                break;
            }
        }
        if break_at == start {
            break_at = end;
        }
        result.push(chars[start..break_at].iter().collect());
        start = break_at;
        while start < chars.len() && chars[start] == ' ' {
            start += 1;
        }
    }
    result
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_content_splits_code_blocks() {
        let input = "hello\n```rust\nfn main() {}\n```\nbye";
        let segs = parse_content(input);
        assert_eq!(segs.len(), 3);
        match &segs[1] {
            ContentSegment::Code { lang, code } => {
                assert_eq!(lang, "rust");
                assert_eq!(code, "fn main() {}");
            }
            _ => panic!("expected code segment"),
        }
    }

    #[test]
    fn detect_links_finds_urls() {
        let cwd = std::path::Path::new("/tmp");
        let links = detect_links("visit https://example.com for info", cwd);
        assert_eq!(links.len(), 1);
        assert_eq!(links[0].start, 6);
        match &links[0].target {
            LinkTarget::Url(url) => assert_eq!(url, "https://example.com"),
            _ => panic!("expected url"),
        }
    }

    #[test]
    fn wrap_line_handles_unicode() {
        let text = "héllo wörld tëst";
        let wrapped = wrap_line(text, 7);
        assert!(!wrapped.is_empty());
    }
}

