/// Extract selected text from chat rows and copy to macOS clipboard
fn copy_chat_selection_to_clipboard(state: &AppState) {
    let sel = match &state.chat_selection {
        Some(s) => s,
        None => return,
    };

    // Normalize: start <= end
    let (sr, sc, er, ec) = if sel.start_row < sel.end_row
        || (sel.start_row == sel.end_row && sel.start_col <= sel.end_col)
    {
        (sel.start_row, sel.start_col, sel.end_row, sel.end_col)
    } else {
        (sel.end_row, sel.end_col, sel.start_row, sel.start_col)
    };

    let mut lines: Vec<String> = Vec::new();

    for &(row, ref text) in &state.chat_row_text {
        if row < sr || row > er {
            continue;
        }
        let chars: Vec<char> = text.chars().collect();
        // We need to figure out where this row starts on screen.
        // chat_row_text stores (screen_row, plain_text).
        // The selection cols are screen-absolute, but text is the full line content.
        // For simplicity, use the chat_area_rect.x as the base.
        let base_x = state.chat_area_rect.x;
        let start_char = if row == sr {
            (sc.saturating_sub(base_x)) as usize
        } else {
            0
        };
        let end_char = if row == er {
            (ec.saturating_sub(base_x)) as usize
        } else {
            chars.len()
        };
        let start_char = start_char.min(chars.len());
        let end_char = end_char.min(chars.len());
        if end_char > start_char {
            let selected: String = chars[start_char..end_char].iter().collect();
            lines.push(selected);
        } else {
            lines.push(String::new());
        }
    }

    let text = lines.join("\n");
    if text.is_empty() {
        return;
    }

    // Copy to clipboard via pbcopy (macOS)
    if let Ok(mut child) = std::process::Command::new("pbcopy")
        .stdin(std::process::Stdio::piped())
        .spawn()
    {
        if let Some(stdin) = child.stdin.as_mut() {
            let _ = stdin.write_all(text.as_bytes());
        }
        let _ = child.wait();
    }
}

