#[allow(dead_code)]
#[derive(Debug, Clone, PartialEq)]
pub enum MessageRole { User, Assistant, System, ToolUse, ToolResult }

#[derive(Debug, Clone)]
pub struct InputState {
    pub lines: Vec<String>,
    pub cursor_line: usize,
    pub cursor_col: usize,
    pub selection: Option<Selection>,
    pub scroll_offset: usize,
    /// Anchor for shift-selection: where selection started
    pub selection_anchor: Option<(usize, usize)>,
}

impl InputState {
    pub fn new() -> Self {
        Self { lines: vec![String::new()], cursor_line: 0, cursor_col: 0, selection: None, scroll_offset: 0, selection_anchor: None }
    }
    pub fn text(&self) -> String { self.lines.join("\n") }

