        let tx = agent_task::spawn_agent(
            state.tabs[0].id.clone(),
            state.cwd.to_string_lossy().to_string(),
            settings.default_model.clone(),
            event_tx.clone(),
        );
        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
            *agent_tx = Some(tx);
        }
    }

    // Initial git refresh
    let _ = event_tx.send(AppEvent::GitRefresh).await;

    // Spawn git watcher
    let etx_git = event_tx.clone();
    tokio::spawn(async move {
        loop {
            tokio::time::sleep(Duration::from_secs(5)).await;
            let _ = etx_git.send(AppEvent::GitRefresh).await;
        }
    });

    // Watch cwd for file system changes — refresh file tree instantly
    {
        use notify::{Config, RecommendedWatcher, RecursiveMode, Watcher};
        use std::sync::mpsc as std_mpsc;

        let watch_dir = state.cwd.clone();
        let etx_files = event_tx.clone();

        tokio::task::spawn_blocking(move || {
            let (tx, rx) = std_mpsc::channel();
            let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
                Ok(w) => w,
                Err(_) => return,
            };
            if watcher.watch(&watch_dir, RecursiveMode::Recursive).is_err() {
                return;
            }
            let mut last_sent = std::time::Instant::now()
                .checked_sub(Duration::from_secs(1))
                .unwrap_or(std::time::Instant::now());
            loop {
                match rx.recv() {
                    Ok(Ok(_)) => {
                        if last_sent.elapsed() >= Duration::from_millis(300) {
                            last_sent = std::time::Instant::now();
                            let _ = etx_files.blocking_send(AppEvent::FileTreeRefresh);
                        }
                    }
                    Ok(Err(_)) | Err(_) => break,
                }
            }
        });
    }

    // Watch ~/.claude/projects/ for new/changed JSONL — refresh sessions instantly
    {
        use notify::{Config, RecommendedWatcher, RecursiveMode, Watcher};
        use std::sync::mpsc as std_mpsc;

        let projects_dir = clui_config::Paths::new().claude_projects_dir;
        let etx_sessions = event_tx.clone();

        // notify uses std channels; bridge to tokio via blocking spawn
        tokio::task::spawn_blocking(move || {
            let (tx, rx) = std_mpsc::channel();
            let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
                Ok(w) => w,
                Err(_) => return,
            };
            if watcher.watch(&projects_dir, RecursiveMode::Recursive).is_err() {
                return;
            }
            // Debounce: don't send more than 1 refresh per 500ms
            let mut last_sent = std::time::Instant::now()
                .checked_sub(Duration::from_secs(1))
                .unwrap_or(std::time::Instant::now());
            loop {
                match rx.recv() {
                    Ok(Ok(event)) => {
                        // Only care about .jsonl file changes
                        let is_jsonl = event.paths.iter().any(|p| {
                            p.extension().and_then(|e| e.to_str()) == Some("jsonl")
                        });
                        if is_jsonl && last_sent.elapsed() >= Duration::from_millis(500) {
                            last_sent = std::time::Instant::now();
                            let _ = etx_sessions.blocking_send(AppEvent::SessionsRefresh);
                        }
                    }
                    Ok(Err(_)) | Err(_) => break,
                }
            }
        });
    }

    loop {
        terminal.draw(|f| ui::render(f, state))?;

        // Drain async events
        while let Ok(evt) = event_rx.try_recv() {
            router::handle(state, evt);
        }

        if crossterm_poll(Duration::from_millis(16))? {
            match crossterm_read()? {
                Event::Key(k) if k.kind == crossterm::event::KeyEventKind::Press => {
                    router::handle(state, AppEvent::Key {
                        code: k.code,
                        modifiers: k.modifiers,
                    });
                }
                Event::Key(_) => {} // ignore Release and Repeat
                Event::Mouse(m) => router::handle(
                    state,
                    AppEvent::Mouse {
                        kind: m.kind,
                        col: m.column,
                        row: m.row,
                        modifiers: m.modifiers,
                    },
                ),
                Event::Resize(c, r) => {
                    router::handle(state, AppEvent::Resize { cols: c, rows: r })
                }
                _ => {}
            }
        } else {
            router::handle(state, AppEvent::Tick);
        }

        // Dispatch pending prompts to agent
        if let Some(tab) = state.active_tab_mut() {
            if let Some(prompt) = tab.pending_prompt.take() {
                if let TabKind::Chat {
                    agent_tx: Some(tx),
                } = &tab.kind
                {
                    let _ = tx
                        .send(agent_task::AgentCommand::SendPrompt { text: prompt })
                        .await;
                }
            }
        }

        if state.should_quit {
            break;
        }
    }
    Ok(())
}

