fn paste_from_clipboard(state: &mut AppState) {
    let output = match std::process::Command::new("pbpaste").output() {
        Ok(o) => o,
        Err(_) => return,
    };
    let text = String::from_utf8_lossy(&output.stdout);
    if text.is_empty() {
        return;
    }
    if let Some(tab) = state.active_tab_mut() {
        let input = &mut tab.input;
        let paste_lines: Vec<&str> = text.split('\n').collect();
        for (i, chunk) in paste_lines.iter().enumerate() {
            // Insert chunk into current line at cursor
            let chars: Vec<char> = input.lines[input.cursor_line].chars().collect();
            let before: String = chars[..input.cursor_col].iter().collect();
            let after: String = chars[input.cursor_col..].iter().collect();
            input.lines[input.cursor_line] = format!("{}{}{}", before, chunk, after);
            input.cursor_col += chunk.chars().count();
            // If not the last chunk, split into new line
            if i < paste_lines.len() - 1 {
                let current_line = input.lines[input.cursor_line].clone();
                let chars: Vec<char> = current_line.chars().collect();
                let left: String = chars[..input.cursor_col].iter().collect();
                let right: String = chars[input.cursor_col..].iter().collect();
                input.lines[input.cursor_line] = left;
                input.cursor_line += 1;
                input.lines.insert(input.cursor_line, right);
                input.cursor_col = 0;
            }
        }
        input.selection = None;
        input.selection_anchor = None;
    }
}

